#include "biblia.h"

void Biblia::CarregarOseias(Biblia* b) {
    b->dados[OSEIAS].nome = wxT("Oseias");

    b->dados[OSEIAS].capitulos[1].versos[1] = wxT("A palavra do Senhor, que veio a Oséias, filho de Beeri, nos dias de Uzias, Jotão, Acaz e Ezequias, reis de Judá, e nos dias de Jeroboão, filho de Joás, rei de Israel.");
    b->dados[OSEIAS].capitulos[1].versos[2] = wxT("Quando o Senhor falou no princípio por Oséias, disse o Senhor a Oséias: Vai, toma por esposa uma mulher de prostituições, e filhos de prostituição; porque a terra se prostituiu, apartando-se do Senhor.");
    b->dados[OSEIAS].capitulos[1].versos[3] = wxT("Ele se foi, pois, e tomou a Gomer, filha de Diblaim; e ela concebeu, e lhe deu um filho.");
    b->dados[OSEIAS].capitulos[1].versos[4] = wxT("E disse-lhe o Senhor: Põe-lhe o nome de Jizreel; porque daqui a pouco visitarei o sangue de Jizreel sobre a casa de Jeú, e farei cessar o reino da casa de Israel.");
    b->dados[OSEIAS].capitulos[1].versos[5] = wxT("E naquele dia quebrarei o arco de Israel no vale de Jizreel.");
    b->dados[OSEIAS].capitulos[1].versos[6] = wxT("E tornou ela a conceber, e deu à luz uma filha. E o Senhor disse a Oséias: Põe-lhe o nome de Lo-Ruama; porque não tornarei mais a compadecer-me da casa de Israel, nem a perdoar-lhe de maneira alguma.");
    b->dados[OSEIAS].capitulos[1].versos[7] = wxT("Mas da casa se Judá me compadecerei, e os salvarei pelo Senhor seu Deus, pois não os salvarei pelo arco, nem pela espada, nem pela guerra, nem pelos cavalos, nem pelos cavaleiros.");
    b->dados[OSEIAS].capitulos[1].versos[8] = wxT("Ora depois de haver desmamado a Lo-Ruama, concebeu e deu à luz um filho.");
    b->dados[OSEIAS].capitulos[1].versos[9] = wxT("E o Senhor disse: Põe-lhe o nome de Lo-Ami; porque vós não sois meu povo, nem sou eu vosso Deus.");
    b->dados[OSEIAS].capitulos[1].versos[10] = wxT("Todavia o número dos filhos de Israel será como a areia do mar, que não pode ser medida nem contada; e no lugar onde se lhes dizia: Vós não sois meu povo, se lhes dirá: Vós sois os filhos do Deus vivo.");
    b->dados[OSEIAS].capitulos[1].versos[11] = wxT("E os filhos de Judá e os filhos de Israel juntos se congregarão, e constituirão sobre si uma só cabeça, e subirão da terra; pois grande será o dia de Jizreel.");

    b->dados[OSEIAS].capitulos[2].versos[1] = wxT("Dizei a vossos irmãos: Ami; e a vossas irmãs: Ruama.");
    b->dados[OSEIAS].capitulos[2].versos[2] = wxT("Contendei com vossa mãe, contendei; porque ela não é minha mulher, e eu não sou seu marido; para que ela afaste as suas prostituições da sua face e os seus adultérios de entre os seus seios;");
    b->dados[OSEIAS].capitulos[2].versos[3] = wxT("para que eu não a deixe despida, e a ponha como no dia em que nasceu, e a faça como um deserto, e a torne como uma terra seca, e a mate à sede.");
    b->dados[OSEIAS].capitulos[2].versos[4] = wxT("Até de seus filhos não me compadecerei; porquanto são filhos de prostituições.");
    b->dados[OSEIAS].capitulos[2].versos[5] = wxT("porque sua mãe se prostituiu; aquela que os concebeu houve-se torpemente; porque diz: Irei após os meus amantes, que me dão o meu pão e a minha água, a minha lã e o meu linho, o meu óleo e as minhas bebidas.");
    b->dados[OSEIAS].capitulos[2].versos[6] = wxT("Portanto, eis que lhe cercarei o caminho com espinhos, e contra ela levantarei uma sebe, para que ela não ache as suas veredas.");
    b->dados[OSEIAS].capitulos[2].versos[7] = wxT("Ela irá em seguimento de seus amantes, mas não os alcançará; buscá-los-á, mas não os achará; então dirá: Irei, e voltarei a meu primeiro marido, porque melhor me ia então do que agora.");
    b->dados[OSEIAS].capitulos[2].versos[8] = wxT("Ora, ela não reconhece que fui eu o que lhe dei o grão, e o vinho, e o azeite, e que lhe multipliquei a prata e o ouro, que eles usaram para Baal.");
    b->dados[OSEIAS].capitulos[2].versos[9] = wxT("Portanto, tornarei a tirar o meu grão a seu tempo e o meu vinho no seu tempo determinado; e arrebatarei a minha lã e o meu linho, com que cobriam a sua nudez.");
    b->dados[OSEIAS].capitulos[2].versos[10] = wxT("E agora descobrirei a sua vileza diante dos olhos dos seus amantes, e ninguém a livrará da minha mão.");
    b->dados[OSEIAS].capitulos[2].versos[11] = wxT("Também farei cessar todo o seu gozo, as suas festas, as suas luas novas, e os seus sábados, e todas as suas assembléias solenes.");
    b->dados[OSEIAS].capitulos[2].versos[12] = wxT("E devastarei a sua vide e a sua figueira, de que ela diz: É esta a paga que me deram os meus amantes; eu, pois, farei delas um bosque, e as feras do campo as devorarão.");
    b->dados[OSEIAS].capitulos[2].versos[13] = wxT("Castigá-la-ei pelos dias dos baalins, nos quais elas lhes queimava incenso, e se adornava com as suas arrecadas e as suas jóias, e, indo atrás dos seus amantes, se esquecia de mim, diz o Senhor.");
    b->dados[OSEIAS].capitulos[2].versos[14] = wxT("Portanto, eis que eu a atrairei, e a levarei para o deserto, e lhe falarei ao coração.");
    b->dados[OSEIAS].capitulos[2].versos[15] = wxT("E lhe darei as suas vinhas dali, e o vale de Acor por porta de esperança; e ali responderá, como nos dias da sua mocidade, e como no dia em que subiu da terra do Egito.");
    b->dados[OSEIAS].capitulos[2].versos[16] = wxT("E naquele dia, diz o Senhor, ela me chamará meu marido; e não me chamará mais meu Baal.");
    b->dados[OSEIAS].capitulos[2].versos[17] = wxT("Pois da sua boca tirarei os nomes dos baalins, e não mais se fará menção desses nomes.");
    b->dados[OSEIAS].capitulos[2].versos[18] = wxT("Naquele dia farei por eles aliança com as feras do campo, e com as aves do céu, e com os répteis da terra; e da terra tirarei o arco, e a espada, e a guerra, e os farei deitar em segurança.");
    b->dados[OSEIAS].capitulos[2].versos[19] = wxT("E desposar-te-ei comigo para sempre; sim, desposar-te-ei comigo em justiça, e em juízo, e em amorável benignidade, e em misericórdias;");
    b->dados[OSEIAS].capitulos[2].versos[20] = wxT("e desposar-te-ei comigo em fidelidade, e conhecerás ao Senhor.");
    b->dados[OSEIAS].capitulos[2].versos[21] = wxT("Naquele dia responderei, diz o Senhor; responderei aos céus, e estes responderão a terra;");
    b->dados[OSEIAS].capitulos[2].versos[22] = wxT("a terra responderá ao trigo, e ao vinho, e ao azeite, e estes responderão a Jizreel.");
    b->dados[OSEIAS].capitulos[2].versos[23] = wxT("E semeá-lo-ei para mim na terra, e compadecer-me-ei de Lo-Ruama; e a e Lo-Ami direi: Tu és meu povo; e ele dirá: Tu és o meu Deus.");

    b->dados[OSEIAS].capitulos[3].versos[1] = wxT("Disse-me o Senhor: Vai outra vez, ama uma mulher, amada de seu amigo, e adúltera, como o Senhor ama os filhos de Israel, embora eles se desviem para outros deuses, e amem passas de uvas.");
    b->dados[OSEIAS].capitulos[3].versos[2] = wxT("Assim eu comprei para mim tal mulher por quinze peças de prata, e um hômer e meio de cevada;");
    b->dados[OSEIAS].capitulos[3].versos[3] = wxT("e lhe disse: Por muitos dias tu ficarás esperando por mim; não te prostituirás, nem serás mulher de outro homem; assim também eu esperarei por ti.");
    b->dados[OSEIAS].capitulos[3].versos[4] = wxT("Pois os filhos de Israel ficarão por muitos dias sem rei, sem príncipe, sem sacrifício, sem coluna, e sem éfode ou terafins.");
    b->dados[OSEIAS].capitulos[3].versos[5] = wxT("Depois tornarão os filhos de Israel, e buscarão ao Senhor, seu Deus, e a Davi, seu rei; e com temor chegarão nos últimos dias ao Senhor, e à sua bondade.");

    b->dados[OSEIAS].capitulos[4].versos[1] = wxT("Ouvi a palavra do Senhor, vós, filhos de Israel; pois o Senhor tem uma contenda com os habitantes da terra; porque na terra não há verdade, nem benignidade, nem conhecimento de Deus.");
    b->dados[OSEIAS].capitulos[4].versos[2] = wxT("Só prevalecem o perjurar, o mentir, o matar, o furtar, e o adulterar; há violências e homicídios sobre homicídios.");
    b->dados[OSEIAS].capitulos[4].versos[3] = wxT("Por isso a terra se lamenta, e todo o que nela mora desfalece, juntamente com os animais do campo e com as aves do céu; e até os peixes do mar perecem.");
    b->dados[OSEIAS].capitulos[4].versos[4] = wxT("Todavia ninguém contenda, ninguém repreenda; pois é contigo a minha contenda, ó sacerdote.");
    b->dados[OSEIAS].capitulos[4].versos[5] = wxT("Por isso tu tropeçarás de dia, e o profeta contigo tropeçará de noite; e destruirei a tua mãe.");
    b->dados[OSEIAS].capitulos[4].versos[6] = wxT("O meu povo está sendo destruído, porque lhe falta o conhecimento. Porquanto rejeitaste o conhecimento, também eu te rejeitarei, para que não sejas sacerdote diante de mim; visto que te esqueceste da lei do teu Deus, também eu me esquecerei de teus filhos.");
    b->dados[OSEIAS].capitulos[4].versos[7] = wxT("Quanto mais eles se multiplicaram tanto mais contra mim pecaram: eu mudarei a sua honra em vergonha.");
    b->dados[OSEIAS].capitulos[4].versos[8] = wxT("Alimentavam-se do pecado do meu povo, e de coração desejam a iniqüidade dele.");
    b->dados[OSEIAS].capitulos[4].versos[9] = wxT("Por isso, como é o povo, assim será o sacerdote; e castigá-lo-ei conforme os seus caminhos, e lhe darei a recompensa das suas obras.");
    b->dados[OSEIAS].capitulos[4].versos[10] = wxT("Comerão, mas não se fartarão; entregar-se-ão à luxúria, mas não se multiplicarão; porque deixaram de atentar para o Senhor.");
    b->dados[OSEIAS].capitulos[4].versos[11] = wxT("A incontinência, e o vinho, e o mosto tiram o entendimento.");
    b->dados[OSEIAS].capitulos[4].versos[12] = wxT("O meu povo consulta ao seu pau, e a sua vara lhe dá respostas, porque o espírito de luxúria os enganou, e eles, prostituindo-se, abandonam o seu Deus.");
    b->dados[OSEIAS].capitulos[4].versos[13] = wxT("Sacrificam sobre os cumes dos montes; e queimam incenso sobre os outeiros, debaixo do carvalho, do álamo, e do terebinto, porque é boa a sua sombra; por isso vossas filhas se prostituem, e as vossas noras adulteram.");
    b->dados[OSEIAS].capitulos[4].versos[14] = wxT("Eu não castigarei vossas filhas, quando se prostituem, nem vossas noras, quando adulteram; porque os homens mesmos com as prostitutas se desviam, e com as meretrizes sacrificam; pois o povo que não tem entendimento será transtornado.");
    b->dados[OSEIAS].capitulos[4].versos[15] = wxT("Ainda que tu, ó Israel, te queiras prostituir contudo não se faça culpado Judá; não venhais a Gilgal, e não subais a Bete-Ávem nem jureis, dizendo: Vive o Senhor.");
    b->dados[OSEIAS].capitulos[4].versos[16] = wxT("Porque como novilha obstinada se rebelou Israel; agora o Senhor os apascentará como a um cordeiro num lugar espaçoso.");
    b->dados[OSEIAS].capitulos[4].versos[17] = wxT("Efraim está entregue aos ídolos; deixa-o.");
    b->dados[OSEIAS].capitulos[4].versos[18] = wxT("Acabando eles de beber, lançam-se à luxúria; certamente os seus príncipes amam a vergonha.");
    b->dados[OSEIAS].capitulos[4].versos[19] = wxT("Um vento os envolveu nas suas asas; e eles se envergonharão por causa dos seus sacrifícios.");

    b->dados[OSEIAS].capitulos[5].versos[1] = wxT("Ouvi isto, ó sacerdotes, e escutai, ó casa de Israel, e dai ouvidos, ó casa do rei; porque contra vós se dirige este juízo; pois que vos tornastes um laço para Mizpá, e uma rede estendida sobre o Tabor.");
    b->dados[OSEIAS].capitulos[5].versos[2] = wxT("Os revoltosos se aprofundaram na corrupção; mas eu os castigarei a todos eles.");
    b->dados[OSEIAS].capitulos[5].versos[3] = wxT("Eu conheço a Efraim, e Israel não se me esconde; porque agora te tens prostituído, ó Efraim, e Israel se contaminou.");
    b->dados[OSEIAS].capitulos[5].versos[4] = wxT("As suas ações não lhes permitem voltar para o seu Deus; porque o espírito da prostituição está no meio deles, e não conhecem ao Senhor.");
    b->dados[OSEIAS].capitulos[5].versos[5] = wxT("A soberba de Israel testifica contra eles; e Israel e Efraim cairão pela sua iniqüidade, e Judá cairá juntamente com eles.");
    b->dados[OSEIAS].capitulos[5].versos[6] = wxT("Eles irão com os seus rebanhos e com as suas manadas, para buscarem ao Senhor, mas não o acharão; ele se retirou deles.");
    b->dados[OSEIAS].capitulos[5].versos[7] = wxT("Aleivosamente se houveram contra o Senhor, porque geraram filhos estranhos; agora a festa da lua nova os consumirá, juntamente com as suas porções.");
    b->dados[OSEIAS].capitulos[5].versos[8] = wxT("Tocai a corneta em Gibeá, a trombeta em Ramá; soltai o alarma em Bete-Áven; após ti, ó Benjamim.");
    b->dados[OSEIAS].capitulos[5].versos[9] = wxT("Efraim será para assolação no dia do castigo: entre as tribos de Israel declaro o que é certo.");
    b->dados[OSEIAS].capitulos[5].versos[10] = wxT("Os príncipes de Judá são como os que removem os marcos; derramarei, pois, o meu furor sobre eles como água.");
    b->dados[OSEIAS].capitulos[5].versos[11] = wxT("Efraim está oprimido e quebrantado no juízo, porque foi do seu agrado andar após a vaidade.");
    b->dados[OSEIAS].capitulos[5].versos[12] = wxT("Portanto para Efraim serei como a traça e para a casa de Judá como a podridão.");
    b->dados[OSEIAS].capitulos[5].versos[13] = wxT("Quando Efraim viu a sua enfermidade, e Judá a sua chaga, recorreu Efraim à Assíria e enviou ao rei Jarebe; mas ele não pode curar-vos, nem sarar a vossa chaga.");
    b->dados[OSEIAS].capitulos[5].versos[14] = wxT("Pois para Efraim serei como um leão, e como um leão novo para a casa de Judá; eu, sim eu despedaçarei, e ir-me-ei embora; arrebatarei, e não haverá quem livre.");
    b->dados[OSEIAS].capitulos[5].versos[15] = wxT("Irei, e voltarei para o meu lugar, até que se reconheçam culpados e busquem a minha face; estando eles aflitos, ansiosamente me buscarão.");

    b->dados[OSEIAS].capitulos[6].versos[1] = wxT("Vinde, e tornemos para o Senhor, porque ele despedaçou e nos sarará; fez a ferida, e no-la atará.");
    b->dados[OSEIAS].capitulos[6].versos[2] = wxT("Depois de dois dias nos ressuscitará: ao terceiro dia nos levantará, e viveremos diante dele.");
    b->dados[OSEIAS].capitulos[6].versos[3] = wxT("Conheçamos, e prossigamos em conhecer ao Senhor; a sua saída, como a alva, é certa; e ele a nós virá como a chuva, como a chuva serôdia que rega a terra.");
    b->dados[OSEIAS].capitulos[6].versos[4] = wxT("Que te farei, ó Efraim? que te farei, ó Judá? porque o vosso amor é como a nuvem da manhã, e como o orvalho que cedo passa.");
    b->dados[OSEIAS].capitulos[6].versos[5] = wxT("Por isso os abati pelos profetas; pela palavra da minha boca os matei; e os meus juízos a teu respeito sairão como a luz.");
    b->dados[OSEIAS].capitulos[6].versos[6] = wxT("Pois misericórdia quero, e não sacrifícios; e o conhecimento de Deus, mais do que os holocaustos.");
    b->dados[OSEIAS].capitulos[6].versos[7] = wxT("Eles, porém, como Adão, transgrediram o pacto; nisso eles se portaram aleivosamente contra mim.");
    b->dados[OSEIAS].capitulos[6].versos[8] = wxT("Gileade é cidade de malfeitores, está manchada de sangue.");
    b->dados[OSEIAS].capitulos[6].versos[9] = wxT("Como hordas de salteadores que espreitam alguém, assim é a companhia dos sacerdotes que matam no caminho para Siquém; sim, cometem a vilania.");
    b->dados[OSEIAS].capitulos[6].versos[10] = wxT("Vejo uma coisa horrenda na casa de Israel; ali está a prostituição de Efraim; Israel está contaminado.");
    b->dados[OSEIAS].capitulos[6].versos[11] = wxT("Também para ti, ó Judá, está determinada uma ceifa. Ao querer eu trazer do cativeiro o meu povo,");

    b->dados[OSEIAS].capitulos[7].versos[1] = wxT("ao querer eu sarar a Israel, descobrem-se a corrupção de Efraim e as maldades de Samária; porque praticam a falsidade; o ladrão entra, e a horda dos salteadores despoja por fora.");
    b->dados[OSEIAS].capitulos[7].versos[2] = wxT("Não consideram no seu coração que eu me lembro de toda a sua maldade; agora, pois, os cercam as suas obras; diante da minha face estão.");
    b->dados[OSEIAS].capitulos[7].versos[3] = wxT("Com a sua malícia alegram ao rei, e com as suas mentiras aos príncipes.");
    b->dados[OSEIAS].capitulos[7].versos[4] = wxT("Todos eles são adúlteros; são semelhantes ao forno aceso, cujo padeiro cessa de atear o fogo desde o amassar a massa até que seja levedada.");
    b->dados[OSEIAS].capitulos[7].versos[5] = wxT("E no dia do nosso rei os príncipes se tornaram doentes com a excitação do vinho; o rei estendeu a sua mão com escarnecedores.");
    b->dados[OSEIAS].capitulos[7].versos[6] = wxT("Pois têm preparado o coração como um forno, enquanto estão de espreita; toda a noite dorme a sua ira; pela manhã arde como fogo de chama.");
    b->dados[OSEIAS].capitulos[7].versos[7] = wxT("Eles estão todos quentes como um forno, e devoram os seus juízes; todos os seus reis caem; ninguém entre eles há que me invoque.");
    b->dados[OSEIAS].capitulos[7].versos[8] = wxT("Quanto a Efraim, ele se mistura com os povos; Efraim é um bolo que não foi virado.");
    b->dados[OSEIAS].capitulos[7].versos[9] = wxT("Estrangeiros lhe devoram a força, e ele não o sabe; também as cãs se espalham sobre ele, e não o sabe.");
    b->dados[OSEIAS].capitulos[7].versos[10] = wxT("E a soberba de Israel testifica contra ele; todavia, não voltam para o Senhor seu Deus, nem o buscam em tudo isso.");
    b->dados[OSEIAS].capitulos[7].versos[11] = wxT("Pois Efraim é como uma pomba, insensata, sem entendimento; invocam o Egito, vão para a Assíria.");
    b->dados[OSEIAS].capitulos[7].versos[12] = wxT("Quando forem, sobre eles estenderei a minha rede, e como aves do céu os farei descer; castigá-los-ei, conforme o que eles têm ouvido na sua congregação.");
    b->dados[OSEIAS].capitulos[7].versos[13] = wxT("Ai deles! porque se erraram de mim; destruição sobre eles! porque se rebelaram contra mim. Quisera eu remi-los, mas falam mentiras contra mim.");
    b->dados[OSEIAS].capitulos[7].versos[14] = wxT("Não clamam a mim de coração, mas uivam nas suas camas; para o trigo e para o mosto se ajuntam, mas contra mim se rebelam.");
    b->dados[OSEIAS].capitulos[7].versos[15] = wxT("Contudo fui eu que os ensinei, e lhes fortaleci os braços; entretanto maquinam o mal contra mim.");
    b->dados[OSEIAS].capitulos[7].versos[16] = wxT("Eles voltam, mas não para o Altíssimo. Fizeram-se como um arco enganador; caem à espada os seus príncipes, por causa da insolência da sua língua; este será o seu escárnio na terra do Egito.");

    b->dados[OSEIAS].capitulos[8].versos[1] = wxT("Põe a trombeta à tua boca. Ele vem como águia contra a casa do Senhor; porque eles transgrediram o meu pacto, e se rebelaram contra a minha lei.");
    b->dados[OSEIAS].capitulos[8].versos[2] = wxT("E a mim clamam: Deus meu, nós, Israel, te conhecemos.");
    b->dados[OSEIAS].capitulos[8].versos[3] = wxT("Israel desprezou o bem; o inimigo persegui-lo-á.");
    b->dados[OSEIAS].capitulos[8].versos[4] = wxT("Eles fizeram reis, mas não por mim; constituíram príncipes, mas sem a minha aprovação; da sua prata e do seu ouro fizeram ídolos para si, para serem destruídos.");
    b->dados[OSEIAS].capitulos[8].versos[5] = wxT("O teu bezerro, ó Samária, é rejeitado; a minha ira se acendeu contra eles; até quando serão eles incapazes da inocência?");
    b->dados[OSEIAS].capitulos[8].versos[6] = wxT("Pois isso procede de Israel; um artífice o fez, e não é Deus. Será desfeito em pedaços o bezerro de Samária");
    b->dados[OSEIAS].capitulos[8].versos[7] = wxT("Porquanto semeiam o vento, hão de ceifar o turbilhão; não haverá seara, a erva não dará farinha; se a der, tragá-la-ão os estrangeiros.");
    b->dados[OSEIAS].capitulos[8].versos[8] = wxT("Israel foi devorado; agora está entre as nações como um vaso em que ninguém tem prazer.");
    b->dados[OSEIAS].capitulos[8].versos[9] = wxT("Porque subiram à Assíria, qual asno selvagem andando sozinho; mercou Efraim amores.");
    b->dados[OSEIAS].capitulos[8].versos[10] = wxT("Todavia, ainda que eles merquem entre as nações, eu as congregarei; já começaram a ser diminuídos por causa da carga do rei dos príncipes.");
    b->dados[OSEIAS].capitulos[8].versos[11] = wxT("Ainda que Efraim tem multiplicado altares, estes se lhe tornaram altares para pecar.");
    b->dados[OSEIAS].capitulos[8].versos[12] = wxT("Escrevi para ele miríades de coisas da minha lei; mas isso é para ele como coisa estranha.");
    b->dados[OSEIAS].capitulos[8].versos[13] = wxT("Quanto aos sacrifícios das minhas ofertas, eles sacrificam carne, e a comem; mas o Senhor não os aceita; agora se lembrará da iniqüidade deles, e punirá os seus pecados; eles voltarão para o Egito.");
    b->dados[OSEIAS].capitulos[8].versos[14] = wxT("Pois Israel se esqueceu do seu Criador, e edificou palácios, e Judá multiplicou cidades fortificadas. Mas eu enviarei sobre as suas cidades um fogo que consumirá os seus castelos.");

    b->dados[OSEIAS].capitulos[9].versos[1] = wxT("Não te alegres, ó Israel, não exultes como os povos; pois te prostituíste, apartando-te do teu Deus; amaste a paga de meretriz sobre todas as eiras de trigo.");
    b->dados[OSEIAS].capitulos[9].versos[2] = wxT("A eira e o lagar não os manterão, e o vinho novo lhes faltará.");
    b->dados[OSEIAS].capitulos[9].versos[3] = wxT("Na terra do Senhor não permanecerão; mas Efraim tornará ao Egito, e na Assíria comerão comida imunda.");
    b->dados[OSEIAS].capitulos[9].versos[4] = wxT("Não derramarão libações de vinho ao Senhor, nem lhe agradarão com as suas ofertas. O pão deles será como pão de pranteadores; todos os que dele comerem serão imundos; pois o seu pão será somente para o seu apetite; não entrará na casa do Senhor.");
    b->dados[OSEIAS].capitulos[9].versos[5] = wxT("Que fareis vós no dia da solenidade, e no dia da festa do Senhor?");
    b->dados[OSEIAS].capitulos[9].versos[6] = wxT("Porque, eis que eles se foram por causa da destruição, mas o Egito os recolherá, Mênfis os sepultará; as suas coisas preciosas de prata as urtigas as possuirão; espinhos crescerão nas suas tendas.");
    b->dados[OSEIAS].capitulos[9].versos[7] = wxT("Chegaram os dias da punição, chegaram os dias da retribuição; Israel o saberá; o profeta é um insensato, o homem possesso de espírito é um louco; por causa da abundância da tua iniqüidade e do teu grande ódio.");
    b->dados[OSEIAS].capitulos[9].versos[8] = wxT("O profeta é a sentinela de Efraim, o povo do meu Deus; contudo um laço de caçador de aves se acha em todos os seus caminhos, e inimizade na casa do seu Deus.");
    b->dados[OSEIAS].capitulos[9].versos[9] = wxT("Muito profundamente se corromperam, como nos dias de Gibeá; ele se lembrará das iniqüidades deles, e punirá os seus pecados.");
    b->dados[OSEIAS].capitulos[9].versos[10] = wxT("Achei a Israel como uvas no deserto, vi a vossos pais como a fruta temporã da figueira no seu princípio; mas eles foram para Baal-Peor, e se consagraram a essa coisa vergonhosa, e se tornaram abomináveis como aquilo que amaram.");
    b->dados[OSEIAS].capitulos[9].versos[11] = wxT("Quanto a Efraim, a sua glória como ave voará; não haverá nascimento, nem gravidez, nem concepção.");
    b->dados[OSEIAS].capitulos[9].versos[12] = wxT("Ainda que venham criar seus filhos, eu os privarei deles, para que não fique nenhum homem. Ai deles, quando deles eu me apartar!");
    b->dados[OSEIAS].capitulos[9].versos[13] = wxT("Efraim, assim como vi a Tiro, está plantado num lugar aprazível; mas Efraim levará seus filhos ao matador.");
    b->dados[OSEIAS].capitulos[9].versos[14] = wxT("Dá-lhes, ó Senhor; mas que lhes darás? dá-lhes uma madre que aborte e seios ressecados.");
    b->dados[OSEIAS].capitulos[9].versos[15] = wxT("Toda a sua malícia se acha em Gilgal; pois ali é que lhes concebi ódio; por causa da maldade das suas obras lançá-los-ei fora de minha casa. Não os amarei mais; todos os seus príncipes são rebeldes.");
    b->dados[OSEIAS].capitulos[9].versos[16] = wxT("Efraim foi ferido, secou-se a sua raiz; eles não darão fruto; sim, ainda que gerem, eu matarei os frutos desejáveis do seu ventre.");
    b->dados[OSEIAS].capitulos[9].versos[17] = wxT("O meu Deus os rejeitará, porque não o ouviram; e errantes andarão entre as nações.");

    b->dados[OSEIAS].capitulos[10].versos[1] = wxT("Israel é vide frondosa que dá o seu fruto; conforme a abundância do seu fruto, assim multiplicou os altares; conforme a prosperidade da terra, assim fizeram belas colunas.");
    b->dados[OSEIAS].capitulos[10].versos[2] = wxT("O seu coração está dividido, por isso serão culpados; ele derribará os altares deles, e lhes destruirá as colunas.");
    b->dados[OSEIAS].capitulos[10].versos[3] = wxT("Certamente agora dirão: Não temos rei, porque não tememos ao Senhor; e o rei, que pode ele fazer por nós?");
    b->dados[OSEIAS].capitulos[10].versos[4] = wxT("Falam palavras vãs; juram falsamente, fazendo pactos; por isso brota o juízo como erva peçonhenta nos sulcos dos campos.");
    b->dados[OSEIAS].capitulos[10].versos[5] = wxT("Os moradores de Samária serão atemorizados por causa do bezerro de Bete-Áven. O seu povo se lamentará por causa dele, como também prantearão os seus sacerdotes idólatras por causa da sua glória, que se apartou dela.");
    b->dados[OSEIAS].capitulos[10].versos[6] = wxT("Também será ele levado para Assíria como um presente ao rei Jarebe; Efraim ficará confuso, e Israel se envergonhará por causa do seu próprio conselho.");
    b->dados[OSEIAS].capitulos[10].versos[7] = wxT("O rei de Samária será desfeito como a espuma sobre a face da água.");
    b->dados[OSEIAS].capitulos[10].versos[8] = wxT("E os altos de Áven, pecado de Israel, serão destruídos; espinhos e cardos crescerão sobre os seus altares; e dirão aos montes: Cobri-nos! e aos outeiros: Caí sobre nós!");
    b->dados[OSEIAS].capitulos[10].versos[9] = wxT("Desde os dias de Gibeá tens pecado, ó Israel; ali permaneceram; a peleja contra os filhos da iniqüidade não os alcançará em Gibeá.");
    b->dados[OSEIAS].capitulos[10].versos[10] = wxT("Quando eu quiser, castigá-los-ei; e os povos se congregarão contra eles, quando forem castigados pela sua dupla transgressão.");
    b->dados[OSEIAS].capitulos[10].versos[11] = wxT("Porque Efraim era uma novilha domada, que gostava de trilhar; e eu poupava a formosura do seu pescoço; mas porei arreios sobre Efraim; Judá lavrará; Jacó desfará os torrões.");
    b->dados[OSEIAS].capitulos[10].versos[12] = wxT("Semeai para vós em justiça, colhei segundo a misericórdia; lavrai o campo alqueivado; porque é tempo de buscar ao Senhor, até que venha e chova a justiça sobre vós.");
    b->dados[OSEIAS].capitulos[10].versos[13] = wxT("Lavrastes a impiedade, segastes a iniqüidade, e comestes o fruto da mentira; porque confiaste no teu caminho, na multidão dos teus valentes.");
    b->dados[OSEIAS].capitulos[10].versos[14] = wxT("Portanto, entre o teu povo se levantará tumulto de guerra, e todas as tuas fortalezas serão destruídas, como Salmã destruiu a Bete-Arbel no dia da batalha; a mãe ali foi despedaçada juntamente com os filhos.");
    b->dados[OSEIAS].capitulos[10].versos[15] = wxT("Assim vos fará Betel, por causa da vossa grande malícia; de madrugada será o rei de Israel totalmente destruído.");

    b->dados[OSEIAS].capitulos[11].versos[1] = wxT("Quando Israel era menino, eu o amei, e do Egito chamei a meu filho.");
    b->dados[OSEIAS].capitulos[11].versos[2] = wxT("Quanto mais eu os chamava, tanto mais se afastavam de mim; sacrificavam aos baalins, e queimavam incenso às imagens esculpidas.");
    b->dados[OSEIAS].capitulos[11].versos[3] = wxT("Todavia, eu ensinei aos de Efraim a andar; tomei-os nos meus braços; mas não entendiam que eu os curava.");
    b->dados[OSEIAS].capitulos[11].versos[4] = wxT("Atraí-os com cordas humanas, com laços de amor; e fui para eles como os que tiram o jugo de sobre as suas queixadas, e me inclinei para lhes dar de comer.");
    b->dados[OSEIAS].capitulos[11].versos[5] = wxT("Não voltarão para a terra do Egito; mas a Assíria será seu rei; porque recusam converter-se.");
    b->dados[OSEIAS].capitulos[11].versos[6] = wxT("Cairá a espada sobre as suas cidades, e consumirá os seus ferrolhos; e os devorará nas suas fortalezas.");
    b->dados[OSEIAS].capitulos[11].versos[7] = wxT("Porque o meu povo é inclinado a desviar-se de mim; ainda que clamem ao Altíssimo, nenhum deles o exalta.");
    b->dados[OSEIAS].capitulos[11].versos[8] = wxT("Como te deixaria, ó Efraim? como te entregaria, ó Israel? como te faria como Admá? ou como Zeboim? Está comovido em mim o meu coração, as minhas compaixões à uma se acendem.");
    b->dados[OSEIAS].capitulos[11].versos[9] = wxT("Não executarei o furor da minha ira; não voltarei para destruir a Efraim, porque eu sou Deus e não homem, o Santo no meio de ti; eu não virei com ira.");
    b->dados[OSEIAS].capitulos[11].versos[10] = wxT("Andarão após o Senhor; ele bramará como leão; e, bramando ele, os filhos, tremendo, virão do ocidente.");
    b->dados[OSEIAS].capitulos[11].versos[11] = wxT("Também, tremendo, virão como um passarinho os do Egito, e como uma pomba os da terra da Assíria; e os farei habitar em suas casas, diz o Senhor.");
    b->dados[OSEIAS].capitulos[11].versos[12] = wxT("Efraim me cercou com mentira, e a casa de Israel com engano; mas Judá ainda domina com Deus, e com o Santo está fiel.");

    b->dados[OSEIAS].capitulos[12].versos[1] = wxT("Efraim apascenta o vento, segue o vento oriental todo o dia; multiplica a mentira e a destruição; e fazem aliança com a Assíria, e o azeite se leva ao Egito");
    b->dados[OSEIAS].capitulos[12].versos[2] = wxT("O Senhor também com Judá tem contenda, e castigará a Jacó segundo os seus caminhos; segundo as suas obras o recompensará.");
    b->dados[OSEIAS].capitulos[12].versos[3] = wxT("No ventre pegou do calcanhar de seu irmão; e na sua idade varonil lutou com Deus.");
    b->dados[OSEIAS].capitulos[12].versos[4] = wxT("Lutou com o anjo, e prevaleceu; chorou, e lhe fez súplicas. Em Betel o achou, e ali falou Deus com ele;");
    b->dados[OSEIAS].capitulos[12].versos[5] = wxT("sim, o Senhor, o Deus dos exércitos; o Senhor e o seu nome.");
    b->dados[OSEIAS].capitulos[12].versos[6] = wxT("Tu, pois, converte-te a teu Deus; guarda a benevolência e a justiça, e em teu Deus espera sempre.");
    b->dados[OSEIAS].capitulos[12].versos[7] = wxT("Quanto a Canaã, tem nas mãos balança enganadora; ama a opressão.");
    b->dados[OSEIAS].capitulos[12].versos[8] = wxT("Diz Efraim: Certamente eu me tenho enriquecido, tenho adquirido para mim grandes bens; em todo o meu trabalho não acharão em mim iniqüidade alguma que seja pecado.");
    b->dados[OSEIAS].capitulos[12].versos[9] = wxT("Mas eu sou o Senhor teu Deus, desde a terra do Egito; eu ainda te farei habitar de novo em tendas, como nos dias da festa solene.");
    b->dados[OSEIAS].capitulos[12].versos[10] = wxT("Também falei aos profetas, e multipliquei as visões; e pelo ministério dos profetas usei de parábolas.");
    b->dados[OSEIAS].capitulos[12].versos[11] = wxT("Não é Gileade iniqüidade? pura vaidade são eles. Em Gilgal sacrificam bois; os seus altares são como montões de pedras nos sulcos dos campos.");
    b->dados[OSEIAS].capitulos[12].versos[12] = wxT("Jacó fugiu para o campo de Arã, e Israel serviu por uma mulher, sim, por uma mulher guardou o gado.");
    b->dados[OSEIAS].capitulos[12].versos[13] = wxT("Mas o Senhor por meio dum profeta fez subir a Israel do Egito, e por um profeta foi ele preservado.");
    b->dados[OSEIAS].capitulos[12].versos[14] = wxT("Efraim mui amargamente provocou-lhe a ira; portanto sobre ele será deixado o seu sangue, e o seu Senhor fará cair sobre ele o seu opróbrio.");

    b->dados[OSEIAS].capitulos[13].versos[1] = wxT("Quando Efraim falava, tremia-se; foi exaltado em Israel; mas quando ele se fez culpado no tocante a Baal, morreu.");
    b->dados[OSEIAS].capitulos[13].versos[2] = wxT("E agora pecam mais e mais, e da sua prata fazem imagens fundidas, ídolos segundo o seu entendimento, todos eles obra de artífices, e dizem: Oferecei sacrifícios a estes. Homens beijam aos bezerros!");
    b->dados[OSEIAS].capitulos[13].versos[3] = wxT("Por isso serão como a nuvem de manhã, e como o orvalho que cedo passa; como a palha que se lança fora da eira, e como a fumaça que sai pela janela.");
    b->dados[OSEIAS].capitulos[13].versos[4] = wxT("Todavia, eu sou o Senhor teu Deus desde a terra do Egito; portanto não conhecerás outro deus além de mim, porque não há salvador senão eu.");
    b->dados[OSEIAS].capitulos[13].versos[5] = wxT("Eu te conheci no deserto, em terra muito seca.");
    b->dados[OSEIAS].capitulos[13].versos[6] = wxT("Depois eles se fartaram em proporção do seu pasto; e estando fartos, ensoberbeceu-se-lhes o coração, por isso esqueceram de mim.");
    b->dados[OSEIAS].capitulos[13].versos[7] = wxT("Portanto serei para eles como leão; como leopardo espreitarei junto ao caminho;");
    b->dados[OSEIAS].capitulos[13].versos[8] = wxT("Como ursa roubada dos seus cachorros lhes sairei ao encontro, e lhes romperei as teias do coração; e ali os devorarei como leoa; as feras do campo os despedaçarão.");
    b->dados[OSEIAS].capitulos[13].versos[9] = wxT("Destruir-te-ei, ó Israel; quem te pode socorrer?");
    b->dados[OSEIAS].capitulos[13].versos[10] = wxT("Onde está agora o teu rei, para que te salve em todas as tuas cidades? e os teus juízes, dos quais disseste: Dá-me rei e príncipes?");
    b->dados[OSEIAS].capitulos[13].versos[11] = wxT("Dei-te um rei na minha ira, e tirei-o no meu furor.");
    b->dados[OSEIAS].capitulos[13].versos[12] = wxT("A iniqüidade de Efraim está atada, o seu pecado está armazenado.");
    b->dados[OSEIAS].capitulos[13].versos[13] = wxT("Dores de mulher de parto lhe sobrevirão; ele é filho insensato; porque é tempo e não está no lugar em que deve vir à luz.");
    b->dados[OSEIAS].capitulos[13].versos[14] = wxT("Eu os remirei do poder do Seol, e os resgatarei da morte. Onde estão, ó morte, as tuas pragas? Onde está, ó Seol, a tua destruição? A compaixão está escondida de meus olhos.");
    b->dados[OSEIAS].capitulos[13].versos[15] = wxT("Ainda que ele dê fruto entre os seus irmãos, virá o vento oriental, vento do Senhor, subindo do deserto, e secar-se-á a sua nascente, e se estancará a sua fonte; ele saqueará o tesouro de todos os vasos desejáveis.");
    b->dados[OSEIAS].capitulos[13].versos[16] = wxT("Samária levará sobre si a sua culpa, porque se rebelou contra o seu Deus; cairá à espada; seus filhinhos serão despedaçados, e as suas mulheres grávidas serão fendidas.");

    b->dados[OSEIAS].capitulos[14].versos[1] = wxT("Volta, ó Israel, para o Senhor teu Deus; porque pela tua iniqüidade tens caído.");
    b->dados[OSEIAS].capitulos[14].versos[2] = wxT("Tomai convosco palavras, e voltai para o Senhor; dizei-lhe: Tira toda a iniqüidade, e aceita o que é bom; e ofereceremos como novilhos os sacrifícios dos nossos lábios.");
    b->dados[OSEIAS].capitulos[14].versos[3] = wxT("Não nos salvará a Assíria, não iremos montados em cavalos; e à obra das nossas mãos já não diremos: Tu és o nosso Deus; porque em ti o órfão acha a misericórdia.");
    b->dados[OSEIAS].capitulos[14].versos[4] = wxT("Eu sararei a sua apostasia, eu voluntariamente os amarei; porque a minha ira se apartou deles.");
    b->dados[OSEIAS].capitulos[14].versos[5] = wxT("Eu serei para Israel como o orvalho; ele florescerá como o lírio, e lançará as suas raízes como o Líbano.");
    b->dados[OSEIAS].capitulos[14].versos[6] = wxT("Estender-se-ão as suas vergônteas, e a sua formosura será como a da oliveira, a sua fragrância como a do Líbano.");
    b->dados[OSEIAS].capitulos[14].versos[7] = wxT("Voltarão os que habitam à sua sombra; reverdecerão como o trigo, e florescerão como a vide; o seu renome será como o do vinho do Líbano.");
    b->dados[OSEIAS].capitulos[14].versos[8] = wxT("Ó Efraim, que tenho eu com os ídolos? Sou eu que respondo, e cuido de ti. Eu sou como a faia verde; de mim é achado o teu fruto.");
    b->dados[OSEIAS].capitulos[14].versos[9] = wxT("Quem é sábio, para que entenda estas coisas? prudente, para que as saiba? porque os caminhos do Senhor são retos, e os justos andarão neles; mas os transgressores neles cairão.");

}
